```java
import java.util.*;

public static long solve(long[] nums) {
    int n = nums.length;
    if (n == 1) return 0;

    // Precompute primes up to the maximum number in nums using Sieve of Eratosthenes
    long maxNum = 0;
    for (long num : nums) {
        if (num > maxNum) {
            maxNum = num;
        }
    }
    boolean[] isPrime = new boolean[(int) (maxNum + 1)];
    Arrays.fill(isPrime, true);
    isPrime[0] = isPrime[1] = false;
    for (int i = 2; i * i <= maxNum; i++) {
        if (isPrime[i]) {
            for (int j = i * i; j <= maxNum; j += i) {
                isPrime[j] = false;
            }
        }
    }

    // Build a map from primes to their multiples' indices
    Map<Long, List<Integer>> primeToIndices = new HashMap<>();
    for (int i = 0; i < n; i++) {
        long num = nums[i];
        if (isPrime[(int) num]) {
            primeToIndices.computeIfAbsent(num, k -> new ArrayList<>()).add(i);
        }
    }

    // BFS setup
    Queue<Integer> queue = new LinkedList<>();
    int[] dist = new int[n];
    Arrays.fill(dist, -1);
    queue.offer(0);
    dist[0] = 0;

    while (!queue.isEmpty()) {
        int current = queue.poll();
        if (current == n - 1) {
            return dist[current];
        }

        // Check adjacent moves
        int[] neighbors = {current - 1, current + 1};
        for (int neighbor : neighbors) {
            if (neighbor >= 0 && neighbor < n && dist[neighbor] == -1) {
                dist[neighbor] = dist[current] + 1;
                queue.offer(neighbor);
            }
        }

        // Check prime teleportation
        long num = nums[current];
        if (num <= maxNum && isPrime[(int) num]) {
            List<Integer> indices = primeToIndices.get(num);
            if (indices != null) {
                for (int j : indices) {
                    if (j != current && dist[j] == -1) {
                        dist[j] = dist[current] + 1;
                        queue.offer(j);
                    }
                }
            }
        }
    }

    return dist[n - 1];
}
